if (msg.payload !== 'on' && msg.payload !== 'off') {
    node.warn('Rejected invalid toggle payload: ' + msg.payload);
    node.status({fill:'red', shape:'ring', text:'bad payload: ' + msg.payload});
    return null;
}
const now = Date.now();
const last = flow.get('last_toggle_ts') || 0;
if (now - last < 2000) {
    node.status({fill:'grey', shape:'ring', text:'debounced'});
    return null;
}
flow.set('last_toggle_ts', now);
node.status({fill:'blue', shape:'dot', text:`turn_${msg.payload}`});
return msg;

const state = msg.payload;
flow.set('pv_enabled', state === 'on');
if (state === 'off') {
    flow.set('pv_loop_active', false);
    msg.branch = 'toggle_off';
    msg.group = '00 Control';
    node.status({fill:'grey', shape:'dot', text:'disabled'});
} else {
    msg.branch = 'toggle_on';
    msg.group = '00 Control';
    node.status({fill:'green', shape:'dot', text:'enabled'});
}
return msg;

const px = parseFloat(msg.payload);
const lo = parseFloat(msg.threshold_low);
const hi = parseFloat(msg.threshold_high);
msg.price = msg.payload;
if (!isFinite(px) || !isFinite(lo) || !isFinite(hi)) {
    msg.event = 'invalid_input';
    msg.error_detail = `lo=${msg.threshold_low} hi=${msg.threshold_high} px=${msg.payload}`;
    msg.group = '02 Decision';
    return [null, msg];
}
if (lo >= hi) {
    msg.event = 'thresholds_inverted';
    msg.error_detail = `lo=${lo} >= hi=${hi}`;
    msg.group = '02 Decision';
    return [null, msg];
}
msg.price_f = px;
msg.threshold_low_f = lo;
msg.threshold_high_f = hi;
msg.group = '02 Decision';
flow.set('pv_invalid_count', 0);
return [msg, null];

flow.set('pv_loop_active', false);
flow.set('pv_desired', {pv1: 0, pv2: 0, ts: Date.now()});
msg.branch = 'cheap_zero';
msg.group = '03 Low Price';
msg.new_pv1 = 0;
msg.new_pv2 = 0;
return msg;

flow.set('pv_loop_active', false);
flow.set('pv_desired', {pv1: 100, pv2: 100, ts: Date.now()});
msg.branch = 'expensive_full';
msg.group = '04 High Price';
msg.new_pv1 = 100;
msg.new_pv2 = 100;
return msg;

flow.set('pv_loop_active', true);
flow.set('pv_p1_last_branch', '');
flow.set('pv_desired', null); // re-seed from live HA on the next loop tick
msg.branch = 'normal_price';
msg.group = '05 Normal Price';
return msg;

const key = 'pv_invalid_count';
let count = (flow.get(key) || 0) + 1;
flow.set(key, count);
if (count >= 3) {
    msg.event = 'watchdog_fallback';
    msg.error_detail = `${count} consecutive bad ticks`;
    msg.group = '06 Watchdog';
    msg.new_pv1 = 50;
    msg.new_pv2 = 50;
    flow.set('pv_loop_active', false);
    flow.set('pv_desired', {pv1: 50, pv2: 50, ts: Date.now()}); // keep loop base in sync
    flow.set(key, 0); // require a fresh 3 strikes before firing again
    return [null, msg];
}
msg.group = '06 Watchdog';
return [msg, null];

const enabled = flow.get('pv_enabled');
const active  = flow.get('pv_loop_active');
if (enabled === false || !active) {
    return null;
}
return msg;

// Normal-price trim: SoC first, then the P1 deadband.
// While SoC < 95% the limiter is driven straight to 100% (deadband
// ignored). In the normal-price band the loop checks battery SoC first:
//     SoC < 95% -> set the limiter to 100% (full output) to charge.
//     SoC > 95% -> trim the limiter DOWN, but only when grid power is outside
//                  the deadband (hold while inside).
//     SoC = 95% -> hold.
// Uses a flow-maintained desired setpoint (pv_desired) as the source of
// truth instead of reading the slider back from HA every tick (avoids
// actuator-feedback stalls/oscillation). HA limits are still read to detect a
// manual slider change and to seed the setpoint after (re)activation. Config
// (step/deadband) is read from the flow cache populated by 08 Config Monitoring.

const P1_MAX_ABS = 23000;        // +/-23 kW sanity clamp on the P1 reading
const RESYNC_DELTA = 5;          // % divergence that counts as a manual override
const CACHE_MAX_AGE_MS = 30000;  // ignore a desired setpoint older than this

// #5 Race guard: a price branch may have stopped the loop while the (async)
// HA reads for this tick were in flight - bail out so we don't overwrite 0/100/50.
if (!flow.get('pv_loop_active')) {
    return [null, null, null, null];
}

const p1 = parseFloat(msg.p1_power);
const haS1 = parseFloat(msg.pv1_current);
const haS2 = parseFloat(msg.pv2_current);
const pv2Present = flow.get('pv2_present') === true;
const socRaw = parseFloat(msg.battery_soc);
const SOC_THRESHOLD = 95;   // < threshold -> charge up, > threshold -> trim down
msg.battery_soc_f = isFinite(socRaw) ? socRaw : null;
msg.battery_full  = isFinite(socRaw) && socRaw >= 100;
msg.pv2_present = pv2Present;

// #4 Establish the base setpoint to step from.
const desired = flow.get('pv_desired');
const fresh = desired && isFinite(desired.pv1) && isFinite(desired.pv2)
            && (Date.now() - (desired.ts || 0) < CACHE_MAX_AGE_MS);
let pv1Base, pv2Base;
if (fresh) {
    // Desired setpoint is the source of truth, but resync if a slider was moved
    // externally (manual override / another automation).
    pv1Base = (isFinite(haS1) && Math.abs(haS1 - desired.pv1) > RESYNC_DELTA) ? haS1 : desired.pv1;
    pv2Base = (isFinite(haS2) && Math.abs(haS2 - desired.pv2) > RESYNC_DELTA) ? haS2 : desired.pv2;
} else {
    // No (or stale) setpoint - seed from the live HA reads.
    pv1Base = haS1;
    pv2Base = haS2;
}

// If PV2 is not present, mirror PV1 so the step maths stay valid; the PV2
// service write is gated downstream and never fires when PV2 is absent.
if (!pv2Present) pv2Base = pv1Base;

// Validate everything we need; missing/out-of-range -> watchdog branch.
// PV2's reading is only required when PV2 is actually present.
if (!isFinite(p1) || Math.abs(p1) > P1_MAX_ABS || !isFinite(pv1Base) || (pv2Present && !isFinite(pv2Base)) || !isFinite(socRaw)) {
    msg.branch = 'p1_invalid_input';
    msg.error_detail = `p1=${msg.p1_power} pv1=${msg.pv1_current} pv2=${msg.pv2_current} soc=${msg.battery_soc}`;
    msg.group = '07 P1 Balance Loop';
    return [null, null, null, msg];
}

// #1 Healthy tick -> clear the shared bad-tick counter so the watchdog only
// trips on genuinely consecutive failures.
flow.set('pv_invalid_count', 0);

// #7 Config from flow cache (populated by the 08 Config Monitoring listeners),
// with the same defaults as before if the cache is not yet warm.
const stepRaw = parseFloat(flow.get('cfg_step'));
const dbRaw = parseFloat(flow.get('cfg_deadband'));
const step = isFinite(stepRaw) ? Math.max(1, Math.min(10, stepRaw)) : 2;
const deadband = isFinite(dbRaw) ? Math.max(0, dbRaw) : 100;
const min = 0, max = 100;
const lastBranch = flow.get('pv_p1_last_branch') || '';

function commit(s1, s2, branch, outIndex) {
    msg.new_pv1 = s1; msg.new_pv2 = s2;
    msg.branch = branch; msg.group = '07 P1 Balance Loop';
    flow.set('pv_desired', {pv1: s1, pv2: s2, ts: Date.now()});
    flow.set('pv_p1_last_branch', branch);
    const out = [null, null, null, null];
    out[outIndex] = msg;
    return out;
}
function balanced() {
    msg.branch = 'balanced'; msg.group = '07 P1 Balance Loop';
    flow.set('pv_p1_last_branch', 'balanced');
    return [null, null, (lastBranch !== 'balanced' ? msg : null), null];
}
function reduce() {
    const r1 = Math.max(min, Math.min(max, Math.round(pv1Base - step)));
    const r2 = Math.max(min, Math.min(max, Math.round(pv2Base - step)));
    if (r1 === pv1Base && r2 === pv2Base) return balanced();
    return commit(r1, r2, 'reduce', 0);
}
function increase() {
    const n1 = Math.max(min, Math.min(max, Math.round(pv1Base + step)));
    const n2 = Math.max(min, Math.min(max, Math.round(pv2Base + step)));
    if (n1 === pv1Base && n2 === pv2Base) return balanced();
    return commit(n1, n2, 'increase', 1);
}

// Check SoC first, then the P1 deadband.
const outOfBand = Math.abs(p1) > deadband;

// Battery below 95% -> drive the limiter straight to 100% (full output) to
// charge, regardless of the grid deadband.
if (socRaw < SOC_THRESHOLD) {
    if (pv1Base === 100 && pv2Base === 100) return balanced();
    return commit(100, 100, 'increase', 1);
}

// Battery above 95% -> trim the limiter DOWN, but only when grid power is
// outside the deadband; hold while the grid is inside the band.
if (socRaw > SOC_THRESHOLD) {
    return outOfBand ? reduce() : balanced();
}

// SoC exactly at the threshold -> hold.
return balanced();

// PV Limiter log — pool-heat-pump-style logging.
// Keeps a rolling buffer and publishes it to sensor.pv_limiter_log as both a
// JSON `entries` attribute and a ready-to-render markdown table.

const MAX = 7;
const now = new Date();
const ts = now.toLocaleTimeString('nl-BE', {timeZone: 'Europe/Brussels', hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false}) + '.' + now.getMilliseconds().toString().padStart(3, '0');
let level = 'log', icon = '🔄', flowName = 'PV Limiter', group = msg.group || 'Unknown', nodeName = 'Flow', payload = '';
const branch = msg.branch || msg.event || '';
const socTxt = (msg.battery_soc_f !== undefined && msg.battery_soc_f !== null) ? ` (SoC ${msg.battery_soc_f}%${msg.battery_full ? ' 🔋full' : ''})` : '';
const pvTxt = (msg.pv2_present === false) ? `${msg.new_pv1}%` : `${msg.new_pv1}%/${msg.new_pv2}%`;

if (msg.error) {
    level='error'; icon='❌'; nodeName='Error'; payload=msg.error.message;
}
else if(branch==='startup'){
    icon='ℹ️'; group='00 Control'; nodeName='Flow'; payload='Flow started — logging active';
}
else if(branch==='toggle_on'){
    icon='▶️'; group='00 Control'; nodeName='Control'; payload='PV Limiter enabled';
}
else if(branch==='toggle_off'){
    icon='⏹️'; group='00 Control'; nodeName='Control'; payload='PV Limiter disabled';
}
else if(branch==='cheap_zero'){
    icon='⚡'; group='03 Low Price'; nodeName='Price Check'; payload=`Low price ${(msg.price_f*100).toFixed(2)} ct -> PV 0%`;
}
else if(branch==='expensive_full'){
    icon='💰'; group='04 High Price'; nodeName='Price Check'; payload=`High price ${(msg.price_f*100).toFixed(2)} ct -> PV 100%`;
}
else if(branch==='normal_price'){
    icon='🔁'; group='05 Normal Price'; nodeName='Price Check'; payload=`Normal price ${(msg.price_f*100).toFixed(2)} ct -> P1 Balance active`;
}
else if(branch==='reduce'){
    icon='⬇️'; group='07 P1 Balance Loop'; nodeName='P1 Balance'; payload=`Export ${Math.abs(msg.p1_power)} W -> ${pvTxt}${socTxt}`;
}
else if(branch==='increase'){
    icon='⬆️'; group='07 P1 Balance Loop'; nodeName='P1 Balance'; payload=`Import ${msg.p1_power} W -> ${pvTxt}${socTxt}`;
}
else if(branch==='soc_increase'){
    icon='🔋'; group='07 P1 Balance Loop'; nodeName='P1 Balance'; payload=`Battery charging${socTxt} -> PV up to ${pvTxt}`;
}
else if(branch==='balanced'){
    icon='✅'; group='07 P1 Balance Loop'; nodeName='P1 Balance'; payload=`P1 ${msg.p1_power} W in deadband${socTxt}`;
}
else if(branch==='invalid_input'){
    level='warn'; icon='⚠️'; group='02 Decision'; nodeName='Sanity'; payload=`Invalid input: ${msg.error_detail}`;
}
else if(branch==='thresholds_inverted'){
    level='warn'; icon='⚠️'; group='02 Decision'; nodeName='Sanity'; payload='Inverted thresholds';
}
else if(branch==='p1_invalid_input'){
    level='warn'; icon='⚠️'; group='07 P1 Balance Loop'; nodeName='P1 Calc'; payload=`Sensor error: ${msg.error_detail}`;
}
else if(branch==='config_change'){
    icon='⚙️'; group='08 Config Monitoring'; nodeName='Config';
    payload=`${msg.config_param}: ${msg.old_value} → ${msg.new_value}`;
}
else if(branch==='watchdog_fallback'){
    level='error'; icon='🛑'; group='06 Watchdog'; nodeName='Watchdog'; payload='Fallback to 50%';
}

const entry = {timestamp:ts, icon, level, flow:flowName, group, node:nodeName, payload};
let buf = flow.get('pv_log_buffer') || [];
buf.unshift(entry);
if(buf.length>MAX) buf=buf.slice(0,MAX);
flow.set('pv_log_buffer',buf);

// Build a ready-to-render markdown table (with real newlines) so the
// dashboard card does not depend on YAML folding for row breaks.
const colorFor = (lvl) => lvl === 'log' ? '#1e88e5' : lvl === 'warn' ? 'orange' : lvl === 'error' ? 'red' : '#009ac7';
let md = '| Time |  | Flow | Group | Node | Explanation |\n| :--- | :--- | :--- | :--- | :--- | :--- |\n';
for (const e of buf) {
    md += `| ${e.timestamp} | ${e.icon} | <font color="${colorFor(e.level)}">${e.flow}</font> | ${e.group} | ${e.node} | ${e.payload} |\n`;
}

msg.payload={state:ts, attributes:{friendly_name:'PV Limiter Log', entries:JSON.stringify(buf), markdown: md}};
return msg;

msg.branch = 'startup';
msg.group = '00 Control';
return msg;

// Filter transient HA WebSocket drops out of the PV Limiter log.
// Sits on the wire from the catch-all to 'Build log entry'. Only error
// messages reach here. Real errors pass through unchanged; transient
// connection drops (NoConnectionError / 'Connection lost') are collapsed to
// a single log row per time window so a burst no longer spams the log.

const txt = (msg.error && msg.error.message) ? String(msg.error.message) : '';
const isConn = /NoConnectionError|Connection (lost|closed)|not connected|ECONNREFUSED|ECONNRESET|socket hang up|websocket/i.test(txt);

if (!isConn) {
    // Genuine error - let it through to the log untouched.
    return msg;
}

// Transient HA connection drop. Rate-limit: one consolidated row per window.
const WINDOW_MS = 60000;
const now = Date.now();
const w = flow.get('ha_conn_err_window') || {start: 0, count: 0};

if (now - w.start > WINDOW_MS) {
    // New episode -> emit one clean summary row and open a fresh window.
    flow.set('ha_conn_err_window', {start: now, count: 1});
    msg.error = Object.assign({}, msg.error, {
        message: 'HA connection lost (transient) - repeats suppressed for ' + (WINDOW_MS/1000) + 's'
    });
    node.status({fill:'yellow', shape:'ring', text:'HA reconnecting...'});
    return msg;
}

// Still inside the window -> swallow, keep a running count on the node status.
w.count += 1;
flow.set('ha_conn_err_window', w);
node.status({fill:'yellow', shape:'ring', text:'HA drops suppressed: ' + w.count});
return null;

const PARAM_MAP = {
    'input_number.pv_price_threshold_low':  'Threshold Low',
    'input_number.pv_price_threshold_high': 'Threshold High',
    'input_number.pv_step_size':            'Step Size',
    'input_number.pv_p1_deadband':          'P1 Deadband'
};
const CACHE_MAP = {
    'input_number.pv_price_threshold_low':  'cfg_threshold_low',
    'input_number.pv_price_threshold_high': 'cfg_threshold_high',
    'input_number.pv_step_size':            'cfg_step',
    'input_number.pv_p1_deadband':          'cfg_deadband'
};
const entityId = msg.topic
    || (msg.old_state && msg.old_state.entity_id)
    || (msg.new_state && msg.new_state.entity_id)
    || (msg.data && msg.data.entity_id)
    || (msg.event && msg.event.entity_id)
    || (msg.data && msg.data.new_state && msg.data.new_state.entity_id)
    || '';
// Always refresh the flow cache so the P1 loop can read config without polling HA.
if (CACHE_MAP[entityId]) {
    const v = parseFloat(msg.payload);
    if (isFinite(v)) flow.set(CACHE_MAP[entityId], v);
}
// Skip the deploy-time initial emit and any no-op change (old === new):
// only a genuine value change should be logged.
const oldVal = (msg.old_state && msg.old_state.state);
if (oldVal === undefined || oldVal === null || String(oldVal) === String(msg.payload)) {
    return null;
}
msg.branch       = 'config_change';
msg.group        = '08 Config Monitoring';
msg.config_param = PARAM_MAP[entityId] || entityId || 'Unknown';
msg.old_value    = oldVal;
msg.new_value    = msg.payload;
return msg;

// Only call the PV2 service when PV2 is detected; otherwise bypass
// straight to the next node so the PV1-only chain still completes.
if (flow.get('pv2_present') === true) { return [msg, null]; }
return [null, msg];

// Only call the PV2 service when PV2 is detected; otherwise bypass
// straight to the next node so the PV1-only chain still completes.
if (flow.get('pv2_present') === true) { return [msg, null]; }
return [null, msg];

// Only call the PV2 service when PV2 is detected; otherwise bypass
// straight to the next node so the PV1-only chain still completes.
if (flow.get('pv2_present') === true) { return [msg, null]; }
return [null, msg];

// Only call the PV2 service when PV2 is detected; otherwise bypass
// straight to the next node so the PV1-only chain still completes.
if (flow.get('pv2_present') === true) { return [msg, null]; }
return [null, msg];

// Only call the PV2 service when PV2 is detected; otherwise bypass
// straight to the next node so the PV1-only chain still completes.
if (flow.get('pv2_present') === true) { return [msg, null]; }
return [null, msg];

// Cache whether the PV2 modbus package is present so the rest of the flow
// controls PV2 only when it exists. Driven by binary_sensor.pv2_config_present
// (defined in pv_limiter_control.yaml). Emits on deploy via outputInitially.
const present = (msg.payload === 'on' || msg.payload === true);
flow.set('pv2_present', present);
node.status({fill: present ? 'green' : 'grey', shape: 'dot', text: present ? 'PV2 detected' : 'PV1 only'});
return null;

const version = 'v1.0';
msg.payload = {
    topic: 'pv_limiter/version',
    payload: version,
    retain: true,
    qos: 1
};
node.status({fill:'blue', shape:'dot', text:version});
return msg;
